# server.enable keeps the model resident in VRAM so dictation doesn't race
# ollama for a transient allocation (which intermittently OOM'd).
services.dictation = {
  enable = true;
  model = "small";
  whisperPackage = stablePkgs.whisper-cpp.override { cudaSupport = true; };
  server.enable = true;
};

